  let navOpen = false;
  let esTipoManual = false;
  let filtroActualTipo = "Todos";

  function toggleNav() {
    const s = document.getElementById("sidebar"), m = document.getElementById("main");
    s.style.width = navOpen ? "0" : "250px";
    if(window.innerWidth > 768) { m.style.marginLeft = navOpen ? "0" : "250px"; }
