    document.getElementById('formItem').reset();
    document.getElementById('formNombre').disabled = false;
    document.getElementById('modalTitle').innerText = "Nuevo Item";
    document.getElementById('btnSubmit').innerText = "GUARDAR NUEVO";
    if(esTipoManual) toggleTipoManual();
    openModal('modalItem');
  }

  function prepararEdicion(btn) {
    const fila = btn.closest('tr');
    document.getElementById('modalTitle').innerText = "Editar Item";
    document.getElementById('btnSubmit').innerText = "ACTUALIZAR DATOS";
    const nombre = fila.querySelector('.col-nombre').innerText;
    document.getElementById('formNombre').value = nombre;
    document.getElementById('formNombre').disabled = true;
    document.getElementById('selectTipo').value = fila.querySelector('.col-tipo').innerText.trim();
    document.getElementById('formMedio').value = fila.querySelector('.col-medio').innerText.replace('-', '');
    document.getElementById('formLongitud').value = fila.querySelector('.col-longitud').innerText.replace('-', '');
    document.getElementById('formNumero').value = fila.querySelector('.col-numero').innerText;
    document.getElementById('formNota').value = fila.querySelector('.col-nota').innerText.replace('-', '');
    openModal('modalItem');
  }

