  async function eliminarItem(btn) {
    const fila = btn.closest('tr');
    const nombre = fila.querySelector('.col-nombre').innerText;

    // Confirmación de seguridad
    if (confirm('¿Estás seguro de que deseas eliminar el producto "' + nombre + '"? Esta acción no se puede deshacer.')) {
      try {
        await fetch('https://n8n.tailwind.es/webhook/eliminarItem-inventario-it', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          // Enviamos el nombre para que tu webhook sepa qué fila borrar en Supabase
          body: JSON.stringify({ Nombre: nombre })
        });
        location.reload(); 
      } catch (error) {
        console.error('Error al eliminar:', error);
      }
    }
  }

  function toggleTipoManual() {
    const sel = document.getElementById('selectTipo'), inp = document.getElementById('inputTipoManual');
    esTipoManual = !esTipoManual;
    sel.classList.toggle('hidden'); inp.classList.toggle('hidden');
    document.querySelector('.btn-plus').innerText = esTipoManual ? 'x' : '+';
  }

  function filtrarPorTipo(t) {
    filtroActualTipo = t;
    document.getElementById('view-title').innerText = "Filtrando: " + t;
    ejecutarFiltros();
    if(navOpen) toggleNav();
  }

  function mostrarTodo() {
    filtroActualTipo = "Todos";
    document.getElementById('view-title').innerText = "Inventario General";
    ejecutarFiltros();
    if(navOpen) toggleNav();
  }

  function ejecutarFiltros() {
    const textoBuscado = document.getElementById('searchInput').value.toLowerCase();
    const filas = document.querySelectorAll('.item-row');

    filas.forEach(fila => {
      const contenidoFila = fila.innerText.toLowerCase();
      const tipoFila = fila.getAttribute('data-tipo');
      const coincideTexto = contenidoFila.includes(textoBuscado);
      const coincideTipo = (filtroActualTipo === "Todos" || tipoFila === filtroActualTipo);

      if (coincideTexto && coincideTipo) {
        fila.style.display = '';
      } else {
        fila.style.display = 'none';
      }
    });
  }

  document.getElementById('formItem').onsubmit = async (e) => {
    e.preventDefault();
    document.getElementById('formNombre').disabled = false;
    const data = Object.fromEntries(new FormData(e.target));
    if(esTipoManual) data.Tipo = data.TipoManual;
    delete data.TipoManual;

    try {
      await fetch('https://n8n.tailwind.es/webhook/crearItem-inventario-it', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
      });
      location.reload(); 
    } catch (error) {
      console.error('Error al enviar:', error);
      document.getElementById('formNombre').disabled = true;
    }
  };
</script>
</body>
